import numpy as np
import matplotlib.pyplot as plt

# === Step Decay ===
def step_decay(epoch, initial_lr=0.1, drop=0.1, epochs_per_drop=30):
    return initial_lr * (drop ** np.floor(epoch / epochs_per_drop))

# === Cosine Annealing ===
def cosine_annealing(epoch, total_epochs=100, lr_max=0.1, lr_min=1e-5):
    return lr_min + 0.5 * (lr_max - lr_min) * (1 + np.cos(np.pi * epoch / total_epochs))

# === Cosine with Warm Restarts (SGDR) ===
def cosine_restarts(epoch, lr_max=0.1, lr_min=1e-5, t_0=10, t_mult=2):
    """Cosine with restarts, cycle length multiplies by t_mult"""
    while epoch > t_0:
        epoch -= t_0
        t_0 *= t_mult
    return cosine_annealing(epoch, t_0, lr_max, lr_min)

# === Warmup + Cosine ===
def warmup_cosine(step, warmup_steps=1000, total_steps=10000, lr_max=1e-3, lr_min=1e-5):
    if step < warmup_steps:
        return lr_max * step / warmup_steps
    else:
        progress = (step - warmup_steps) / (total_steps - warmup_steps)
        return lr_min + 0.5 * (lr_max - lr_min) * (1 + np.cos(np.pi * progress))

